let lang=localStorage.getItem('lang')||'en';
let theme=localStorage.getItem('theme')||'system';

// ===== THEME =====
const THEME_ICONS={system:'\u2299',light:'\u2600',dark:'\u263d'};
const THEME_LABELS={system:{en:'System (default)',es:'Sistema (predeterminado)'},light:{en:'Light theme',es:'Tema claro'},dark:{en:'Dark theme',es:'Tema oscuro'}};
function applyTheme(){
  const isDark=theme==='dark'||(theme==='system'&&window.matchMedia('(prefers-color-scheme: dark)').matches);
  document.documentElement.classList.toggle('dark',isDark);
  const icon=document.getElementById('theme-icon');const tip=document.getElementById('theme-tooltip');
  if(icon)icon.textContent=THEME_ICONS[theme];
  if(tip)tip.textContent=THEME_LABELS[theme][lang]||THEME_LABELS[theme].en;
}
function cycleTheme(){const o=['system','light','dark'];theme=o[(o.indexOf(theme)+1)%o.length];localStorage.setItem('theme',theme);applyTheme();}
window.matchMedia&&window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change',applyTheme);

// ===== LANGUAGE =====
function setLang(l){lang=l;localStorage.setItem('lang',l);document.getElementById('btn-en').classList.toggle('active',l==='en');document.getElementById('btn-es').classList.toggle('active',l==='es');document.documentElement.lang=l==='es'?'es':'en';if(typeof renderPage==='function')renderPage();applyTheme();}

// ===== HELPERS =====
function instBadges(ids){
  if(!ids||!ids.length)return '';
  return '<span class="inst-badges">'+ids.map(id=>{
    const i=INSTITUTIONS[id];if(!i)return '';
    const style=i.square?'style="height:2.25rem;max-width:2.25rem"':'';
    if(i.dark)return `<a class="inst-badge" href="${i.href}" target="_blank" rel="noreferrer" title="${i.fullName}" ${style}><img class="light-only" src="${i.light}" alt="${i.fullName}"><img class="dark-only" src="${i.dark}" alt="${i.fullName}"></a>`;
    return `<a class="inst-badge" href="${i.href}" target="_blank" rel="noreferrer" title="${i.fullName}" ${style}><img src="${i.light}" alt="${i.fullName}"></a>`;
  }).join('')+'</span>';
}
function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function fmtDate(iso){return new Date(iso).toLocaleDateString(lang==='es'?'es-ES':'en-GB',{year:'numeric',month:'short',day:'numeric'});}
function roleLabelConf(r){if(lang==='es'){if(r==='talk')return 'Charla presentada';if(r==='defense')return 'Defensa de tesis';return 'Asistente';}if(r==='talk')return 'Contributed talk';if(r==='defense')return 'Thesis defense';return 'Attendee';}
function renderKatex(){if(window.renderMathInElement)setTimeout(()=>renderMathInElement(document.body,{delimiters:[{left:'$$',right:'$$',display:true},{left:'$',right:'$',display:false}],throwOnError:false}),80);}

