function renderSocials(id){const el=document.getElementById(id);if(!el)return;el.innerHTML=SOCIALS.map(s=>`<li class="social-item"><span class="social-label">${esc(s.label)}</span><a class="social-handle" href="${s.href}" target="_blank" rel="noreferrer">${esc(s.handle)} \u2197</a></li>`).join('');}

// ===== FOOTER =====
function renderFooter(){
  const yr=new Date().getFullYear();const upd=new Date().toLocaleDateString(lang==='es'?'es-ES':'en-GB',{month:'long',year:'numeric'});
  const set=lang==='es'?'Compuesto en Computer Modern.':'Set in Computer Modern.';
  const lu=lang==='es'?'\u00daltima actualizaci\u00f3n':'Last updated';
  document.querySelectorAll('[id^="footer-copy"]').forEach(el=>el.textContent=`\u00a9 ${yr} Iv\u00e1n Villegas-P\u00e9rez. ${set}`);
  document.querySelectorAll('[id^="footer-date"]').forEach(el=>el.textContent=`${lu} \u00b7 ${upd}`);
}

// ===== SLIDE VIEWER =====
const _slideState={};
function initSlideViewer(slug,images){
  if(!images||images.length===0)return;
  _slideState[slug]=_slideState[slug]||0;
  updateSlideViewer(slug,images);
}
function updateSlideViewer(slug,images){
  const idx=_slideState[slug]||0;
  const viewer=document.getElementById('sv-'+slug);if(!viewer)return;
  viewer.querySelectorAll('.sv-img').forEach((img,i)=>img.classList.toggle('sv-hidden',i!==idx));
  const ctr=document.getElementById('sv-ctr-'+slug);if(ctr)ctr.textContent=`${idx+1} / ${images.length}`;
  const bar=document.getElementById('sv-bar-'+slug);if(bar)bar.style.width=`${((idx+1)/images.length)*100}%`;
  const prev=document.getElementById('sv-prev-'+slug);if(prev)prev.disabled=idx===0;
  const next=document.getElementById('sv-next-'+slug);if(next)next.disabled=idx===images.length-1;
}
function slidePrev(slug,images){if(_slideState[slug]>0){_slideState[slug]--;updateSlideViewer(slug,images);}}
function slideNext(slug,images){if(_slideState[slug]<images.length-1){_slideState[slug]++;updateSlideViewer(slug,images);}}

// ===== SLIDES WIDGET =====
function slidesWidget(c){
  const es=lang==='es';
  const abs=`<div class="slides-abstract">${esc(es?DM_ABSTRACT_ES:DM_ABSTRACT_EN)}</div>`;
  const images=c.slideImages||[];
  const noSlides=es?'Diapositivas pr\u00f3ximamente':'Slides coming soon';
  const pdfLabel=es?'Descargar PDF \u2193':'Download PDF \u2193';

  if(images.length===0){
    const pdfLink=c.slidesPdf?`<div style="margin-top:1rem"><a class="btn-outline" style="font-size:.8125rem;padding:.375rem .875rem" href="${c.slidesPdf}" target="_blank" rel="noopener">${es?'Ver PDF \u2197':'View PDF \u2197'}</a> <a class="link-muted" style="font-family:var(--mono);font-size:.75rem" href="${c.slidesPdf}" download>${pdfLabel}</a></div>`:'';
    return abs+`<div class="sv-nofiles"><p style="font-style:italic;color:var(--muted-fg)">${noSlides}</p>${pdfLink}</div>`;
  }

  const slug=c.slug;
  const dir=c.slidesDir||'';
  const imgHtml=images.map((img,i)=>`<img class="sv-img${i>0?' sv-hidden':''}" src="${dir}${img}" alt="${es?'Diapositiva':'Slide'} ${i+1}" loading="${i<2?'eager':'lazy'}">`).join('');
  const prevLabel=es?'Anterior':'Prev';const nextLabel=es?'Siguiente':'Next';
  const viewSrc=es?'Ver fuente \u2197':'View source \u2197';

  return abs+`<div class="sv-wrap" id="sv-${slug}">
  <div class="sv-progress"><div class="sv-bar" id="sv-bar-${slug}" style="width:${Math.round(100/images.length)}%"></div></div>
  <div class="sv-viewport">${imgHtml}</div>
  <div class="sv-controls">
    <button class="sv-btn" id="sv-prev-${slug}" onclick="slidePrev('${slug}',CONFERENCES.find(c=>c.slug==='${slug}').slideImages)" disabled>\u2190 ${prevLabel}</button>
    <div style="text-align:center">
      <div class="sv-counter" id="sv-ctr-${slug}">1 / ${images.length}</div>
      ${c.slidesPdf?`<a class="sv-pdf-link" href="${c.slidesPdf}" download>${pdfLabel}</a>`:''}
    </div>
    <button class="sv-btn" id="sv-next-${slug}" onclick="slideNext('${slug}',CONFERENCES.find(c=>c.slug==='${slug}').slideImages)">${nextLabel} \u2192</button>
  </div>
</div>`;
}

// ===== FULL TEXT =====
function renderFullText(p){
  const es=lang==='es';const ft=FULL_TEXTS[p.fullText];
  if(!ft)return`<p style="color:var(--muted-fg);font-style:italic;padding:2rem 0">${es?'Texto completo pr\u00f3ximamente.':'Full text coming soon.'}</p>`;
  const kicker=es?`${p.natureEs} \u00b7 ${p.contextEs}`:`${p.nature} \u00b7 ${p.context}`;
  const title=es&&p.titleEs?p.titleEs:p.title;
  const pplLabel=p.peopleLabel==='Co-authors'?(es?'Coautores':'Co-authors'):(es?'Tutores':'Supervisors');
  const people=p.collaborators.map(c=>`${esc(c.name)} (${esc(es&&c.roleEs?c.roleEs:c.role)})`).join(', ');
  let html=`<div class="ft-header"><p class="ft-kicker">${esc(kicker)}</p><h2 class="ft-title">${esc(title)}</h2><p class="ft-byline">Iv\u00e1n Villegas-P\u00e9rez \u2014 <em>${esc(pplLabel)}:</em> ${esc(people)}</p><div class="ft-sidebar">${p.reportPdf?`<a class="btn-outline" style="font-size:.8125rem;padding:.375rem .875rem" href="${p.reportPdf}" target="_blank" rel="noopener">${es?'Leer PDF \u2197':'Read PDF \u2197'}</a>`:''}<a class="btn-outline" style="font-size:.8125rem;padding:.375rem .875rem" href="${p.githubUrl}" target="_blank" rel="noopener">GitHub \u2197</a>${instBadges(p.institutions)}</div></div>`;
  ft.sections.forEach(sec=>{
    html+=`<div class="ft-section"><h2 class="ft-h2">${esc(es?sec.h2es:sec.h2en)}</h2>`;
    sec.content.forEach(item=>{
      if(item.type==='p')html+=`<p class="ft-p">${esc(es?item.es:item.en)}</p>`;
      else if(item.type==='h3')html+=`<h3 class="ft-h3">${esc(es?item.es:item.en)}</h3>`;
      else if(item.type==='math')html+=`<div class="ft-math">$$${item.tex}$$</div>`;
      else if(item.type==='note')html+=`<div class="ft-note">${esc(es?item.es:item.en)}</div>`;
      else if(item.type==='figure'){const fig=p.figures[item.idx];if(fig)html+=`<figure class="ft-figure"><img src="${p.figurePrefix}${fig.src}" alt="Fig. ${fig.num}" loading="lazy"><figcaption>Fig. ${fig.num}. ${esc(es?fig.captionEs:fig.captionEn)}</figcaption></figure>`;}
    });
    html+='</div>';
  });
  return html;
}
